
/* ════ 4D TORUS PARALLAX ════
   Segmented stardust torus (faceted ring of panels) that tumbles through its
   own centre — the classic "4th dimension" illusion. Hand-rolled 3D on canvas,
   no libraries. Idle: continuous tumble in place. On scroll: the whole object
   travels DOWN the page with your scroll position (parallax backdrop). */
(function(){
  const canvas=document.getElementById('mesh-canvas');
  const ctx=canvas.getContext('2d');
  const reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  let W,H,dpr=1;

  const WHITE=(a)=>`rgba(240,240,248,${a})`;
  const BLUE=(a)=>`rgba(61,90,254,${a})`;
  const CYAN=(a)=>`rgba(0,229,255,${a})`;

  /* ── Faceted torus: NU panels around the ring × NV around the tube ── */
  const NU=14, NV=6, RMAJ=1.0, RTUBE=0.44, GAP=0.10;
  const panels=[];
  for(let i=0;i<NU;i++){
    for(let j=0;j<NV;j++){
      const u0=(i+GAP/2)/NU*Math.PI*2, u1=(i+1-GAP/2)/NU*Math.PI*2;
      const v0=(j+GAP/2)/NV*Math.PI*2, v1=(j+1-GAP/2)/NV*Math.PI*2;
      /* stardust: [u, v, size, isBlue] — a share of the dust glows electric blue */
      const dust=[];
      const n=12+Math.floor(((i*7+j*13)%12));    /* deterministic count */
      let seed=i*131+j*17+1;
      const rnd=()=>{seed=(seed*16807)%2147483647;return seed/2147483647;};
      for(let k=0;k<n;k++)dust.push([u0+(u1-u0)*rnd(), v0+(v1-v0)*rnd(), 0.4+rnd()*0.9, rnd()<0.28?1:0]);
      panels.push({u0,u1,v0,v1,dust,blueEdge:(i*NV+j)%5===0});
    }
  }

  /* Sparse background starfield (slow parallax layer) */
  const stars=[];
  for(let i=0;i<60;i++)stars.push({x:Math.random(),y:Math.random(),depth:0.15+Math.random()*0.45,r:0.4+Math.random()*1.1});

  let mx=0,my=0,tmx=0,tmy=0,t=0,scrollRot=0;

  function resize(){
    dpr=Math.min(window.devicePixelRatio||1,2);
    W=window.innerWidth;H=window.innerHeight;
    canvas.width=W*dpr;canvas.height=H*dpr;
    canvas.style.width=W+'px';canvas.style.height=H+'px';
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }

  /* torus surface point → rotated 3D. vFlow makes panels stream through the
     hole (the "4D" inside-out motion); rx/ry are rigid tumble angles. */
  function torusPoint(u,v,vFlow,rx,ry){
    const vv=v+vFlow;
    const x=(RMAJ+RTUBE*Math.cos(vv))*Math.cos(u);
    const y=RTUBE*Math.sin(vv);
    const z=(RMAJ+RTUBE*Math.cos(vv))*Math.sin(u);
    /* rotate Y then X */
    const cy1=Math.cos(ry),sy1=Math.sin(ry),cx1=Math.cos(rx),sx1=Math.sin(rx);
    const x1=x*cy1+z*sy1, z1=-x*sy1+z*cy1;
    const y2=y*cx1-z1*sx1, z2=y*sx1+z1*cx1;
    return [x1,y2,z2];
  }

  function project(p,R,cx,cy){
    const d=3.6,s=d/(d-p[2]);
    return {x:cx+p[0]*R*s, y:cy-p[1]*R*s, z:p[2]};
  }

  function draw(){
    ctx.clearRect(0,0,W,H);
    const sy=window.scrollY;
    const docH=Math.max(1,document.documentElement.scrollHeight-H);
    const p=Math.min(1,sy/docH);            /* 0 top → 1 bottom of page */

    /* Layer 1 — starfield, drifts slower than the page */
    stars.forEach(s=>{
      const yy=((s.y*H - sy*s.depth*0.25)%H+H)%H;
      ctx.beginPath();ctx.arc(s.x*W,yy,s.r,0,Math.PI*2);
      ctx.fillStyle=WHITE((0.04+s.depth*0.14).toFixed(3));ctx.fill();
    });

    /* Layer 2 — the torus: tumbles in place; scroll carries it down the page */
    const cx=W*0.5 + Math.sin(t*0.25)*W*0.015 + tmx*W*0.01;
    const cy=H*(0.44+0.38*p) + Math.sin(t*0.4)*H*0.008;
    const R=Math.min(W,H)*0.30;
    const vFlow=t*0.5 + scrollRot;           /* panels stream through the hole */
    const rx=0.95+Math.sin(t*0.11)*0.18+tmy*0.06;
    const ry=t*0.07+tmx*0.06;

    /* depth-sort panels so nearer ones draw over farther ones */
    const drawList=panels.map(P=>{
      const um=(P.u0+P.u1)/2, vm=(P.v0+P.v1)/2;
      const m=torusPoint(um,vm,vFlow,rx,ry);
      return {P,z:m[2]};
    }).sort((a,b)=>a.z-b.z);

    const narrow=W<1000;
    ctx.globalAlpha=narrow?0.45:0.8;

    /* soft electric-blue core glow behind the ring */
    const glow=ctx.createRadialGradient(cx,cy,R*0.1,cx,cy,R*1.6);
    glow.addColorStop(0,CYAN(0.06));glow.addColorStop(1,CYAN(0));
    ctx.fillStyle=glow;ctx.fillRect(cx-R*1.6,cy-R*1.6,R*3.2,R*3.2);

    drawList.forEach(({P,z})=>{
      const depth=(z+1.5)/3;                 /* 0 far → 1 near */
      const la=0.10+depth*0.55;
      /* panel outline: 4 edges, sampled so they curve with the surface */
      ctx.beginPath();
      const E=4;
      for(let k=0;k<=E;k++){const q=project(torusPoint(P.u0+(P.u1-P.u0)*k/E,P.v0,vFlow,rx,ry),R,cx,cy);k?ctx.lineTo(q.x,q.y):ctx.moveTo(q.x,q.y);}
      for(let k=1;k<=E;k++){const q=project(torusPoint(P.u1,P.v0+(P.v1-P.v0)*k/E,vFlow,rx,ry),R,cx,cy);ctx.lineTo(q.x,q.y);}
      for(let k=1;k<=E;k++){const q=project(torusPoint(P.u1-(P.u1-P.u0)*k/E,P.v1,vFlow,rx,ry),R,cx,cy);ctx.lineTo(q.x,q.y);}
      for(let k=1;k<=E;k++){const q=project(torusPoint(P.u0,P.v1-(P.v1-P.v0)*k/E,vFlow,rx,ry),R,cx,cy);ctx.lineTo(q.x,q.y);}
      ctx.closePath();
      /* darken panel interior so nearer panels occlude farther ones */
      ctx.fillStyle=`rgba(0,2,4,${(0.55+depth*0.35).toFixed(3)})`;ctx.fill();
      /* every fifth panel carries an electric-blue edge; the rest stay silver */
      ctx.strokeStyle=P.blueEdge?CYAN((la*1.1).toFixed(3)):WHITE(la.toFixed(3));
      ctx.lineWidth=0.7+depth*0.9;ctx.stroke();

      /* inner detail: mid-lines across the panel, faint blue circuitry feel */
      const um=(P.u0+P.u1)/2, vm=(P.v0+P.v1)/2;
      ctx.beginPath();
      for(let k=0;k<=E;k++){const q=project(torusPoint(P.u0+(P.u1-P.u0)*k/E,vm,vFlow,rx,ry),R,cx,cy);k?ctx.lineTo(q.x,q.y):ctx.moveTo(q.x,q.y);}
      ctx.strokeStyle=CYAN((la*0.35).toFixed(3));ctx.lineWidth=0.5;ctx.stroke();
      ctx.beginPath();
      for(let k=0;k<=E;k++){const q=project(torusPoint(um,P.v0+(P.v1-P.v0)*k/E,vFlow,rx,ry),R,cx,cy);k?ctx.lineTo(q.x,q.y):ctx.moveTo(q.x,q.y);}
      ctx.strokeStyle=WHITE((la*0.22).toFixed(3));ctx.lineWidth=0.5;ctx.stroke();

      /* stardust inside the panel — white sparkle with electric-blue motes */
      P.dust.forEach(d=>{
        const q=project(torusPoint(d[0],d[1],vFlow,rx,ry),R,cx,cy);
        const tw=reduced?0.7:0.55+0.45*Math.sin(t*2.2+d[0]*9+d[1]*7); /* twinkle */
        ctx.beginPath();ctx.arc(q.x,q.y,d[2]*(0.5+depth*0.9)*(d[3]?1.3:1),0,Math.PI*2);
        ctx.fillStyle=d[3]?BLUE((la*1.1*tw).toFixed(3)):WHITE((la*0.9*tw).toFixed(3));ctx.fill();
      });
    });
    ctx.globalAlpha=1;
  }

  let frame=0;
  function loop(){
    t+=reduced?0:0.016;
    const target=window.scrollY*0.0018;
    scrollRot+=(target-scrollRot)*0.06;      /* scroll adds extra spin, smoothed */
    tmx+=(mx-tmx)*0.05; tmy+=(my-tmy)*0.05;
    if(++frame%30===0){
      if(Math.abs(W-window.innerWidth)>1||Math.abs(H-window.innerHeight)>1)resize();
    }
    draw();
    requestAnimationFrame(loop);
  }

  window.addEventListener('resize',resize);
  window.addEventListener('mousemove',e=>{mx=e.clientX/W*2-1;my=e.clientY/H*2-1;});
  document.addEventListener('mouseleave',()=>{mx=0;my=0;});
  resize();
  if(reduced){draw();window.addEventListener('scroll',()=>{scrollRot=window.scrollY*0.0018;draw();},{passive:true});}
  else loop();
})();


/* ════ PROCESS GLOBE ════
   "Predictable outcomes" visual: a wireframe globe with the four process
   outcomes pinned to its surface. Auto-rotates; grab it with the mouse (or
   finger) to spin it yourself — momentum carries on when you let go. */
(function(){
  const canvas=document.getElementById('process-globe');
  if(!canvas)return;
  const panel=canvas.parentElement;
  const ctx=canvas.getContext('2d');
  const reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  let W,H,dpr=1;

  const WHITE=(a)=>`rgba(240,240,248,${a})`;
  const BLUE=(a)=>`rgba(0,229,255,${a})`;   /* HUD rebrand: graticule + pins neon cyan */
  const AMBER=(a)=>`rgba(240,160,48,${a})`;

  /* ── Earth landmass: 2° dot grid (180×90 bitset, baked at build time from
     Natural-Earth-derived country polygons) — land renders as dots, sea empty ── */
  const LAND_B64='';
  const landDots=(()=>{
    const bin=atob(LAND_B64);
    const dots=[];
    for(let r=0;r<90;r++)for(let c=0;c<180;c++){
      const idx=r*180+c;
      if(bin.charCodeAt(idx>>3)&(1<<(idx&7))){
        const lat=(90-(r+0.5)*2)*Math.PI/180, lng=(-180+(c+0.5)*2)*Math.PI/180;
        dots.push([Math.cos(lat)*Math.sin(lng), Math.sin(lat), Math.cos(lat)*Math.cos(lng)]);
      }
    }
    return dots;
  })();

  /* ── Country lookup: 2° grid of country indices (baked at build time) ── */
  const COUNTRY_B64='';
  const COUNTRY_NAMES=["Afghanistan","Angola","Albania","United Arab Emirates","Argentina","Armenia","Antarctica","French Southern and Antarctic Lands","Australia","Austria","Azerbaijan","Burundi","Belgium","Benin","Burkina Faso","Bangladesh","Bulgaria","The Bahamas","Bosnia and Herzegovina","Belarus","Belize","Bermuda","Bolivia","Brazil","Brunei","Bhutan","Botswana","Central African Republic","Canada","Switzerland","Chile","China","Ivory Coast","Cameroon","Democratic Republic of the Congo","Republic of the Congo","Colombia","Costa Rica","Cuba","Northern Cyprus","Cyprus","Czech Republic","Germany","Djibouti","Denmark","Dominican Republic","Algeria","Ecuador","Egypt","Eritrea","Spain","Estonia","Ethiopia","Finland","Fiji","Falkland Islands","France","Gabon","United Kingdom","Georgia","Ghana","Guinea","Gambia","Guinea Bissau","Equatorial Guinea","Greece","Greenland","Guatemala","French Guiana","Guyana","Honduras","Croatia","Haiti","Hungary","Indonesia","India","Ireland","Iran","Iraq","Iceland","Israel","Italy","Jamaica","Jordan","Japan","Kazakhstan","Kenya","Kyrgyzstan","Cambodia","South Korea","Kosovo","Kuwait","Laos","Lebanon","Liberia","Libya","Sri Lanka","Lesotho","Lithuania","Luxembourg","Latvia","Morocco","Moldova","Madagascar","Mexico","Macedonia","Mali","Malta","Myanmar","Montenegro","Mongolia","Mozambique","Mauritania","Malawi","Malaysia","Namibia","New Caledonia","Niger","Nigeria","Nicaragua","Netherlands","Norway","Nepal","New Zealand","Oman","Pakistan","Panama","Peru","Philippines","Papua New Guinea","Poland","Puerto Rico","North Korea","Portugal","Paraguay","Qatar","Romania","Russia","Rwanda","Western Sahara","Saudi Arabia","Sudan","South Sudan","Senegal","Solomon Islands","Sierra Leone","El Salvador","Somaliland","Somalia","Republic of Serbia","Suriname","Slovakia","Slovenia","Sweden","Swaziland","Syria","Chad","Togo","Thailand","Tajikistan","Turkmenistan","East Timor","Trinidad and Tobago","Tunisia","Turkey","Taiwan","United Republic of Tanzania","Uganda","Ukraine","Uruguay","United States of America","Uzbekistan","Venezuela","Vietnam","Vanuatu","West Bank","Yemen","South Africa","Zambia","Zimbabwe"];
  const countryGrid=(()=>{const bin=atob(COUNTRY_B64);const g=new Uint8Array(16200);for(let i=0;i<16200;i++)g[i]=bin.charCodeAt(i);return g;})();
  function countryAt(lat,lng){
    const cell=(la,ln)=>{
      const r=Math.min(89,Math.max(0,Math.floor((90-la)/2)));
      const c=((Math.floor((ln+180)/2))%180+180)%180;
      return countryGrid[r*180+c];
    };
    let v=cell(lat,lng);
    if(v)return COUNTRY_NAMES[v-1];
    /* sea cell — look for nearby land (coastal clicks land just offshore) */
    for(let rad=1;rad<=2;rad++)for(let dy=-rad;dy<=rad;dy++)for(let dx=-rad;dx<=rad;dx++){
      v=cell(lat+dy*2,lng+dx*2);
      if(v)return COUNTRY_NAMES[v-1];
    }
    return null;
  }

  /* the four outcomes, pinned around the globe (lat/lng in degrees) */
  const NODES=[
    {lat:18,lng:0,num:'01',label:'DISCOVERY'},
    {lat:-8,lng:90,num:'02',label:'DIAGNOSIS'},
    {lat:14,lng:180,num:'03',label:'PROPOSAL'},
    {lat:-14,lng:270,num:'04',label:'EXECUTION'},
  ];

  let rotY=0.6, rotX=0.30, spin=0.0045, vel=0, dragging=false, lastX=0, lastY=0, t=0;
  let moved=0, pending=null, myPin=null, pins=[];

  /* other visitors' pins (locations only — the API never exposes emails) */
  fetch('/api/globe/pins').then(r=>r.json()).then(d=>{pins=d.pins||[];}).catch(()=>{});
  try{ myPin=JSON.parse(localStorage.getItem('dw_globe_pin')||'null'); }catch(e){}

  /* email form shown after placing a pin */
  const pinForm=document.createElement('div');
  pinForm.style.cssText='position:absolute;left:50%;transform:translateX(-50%);bottom:12px;display:none;background:rgba(0,6,10,0.96);border:1px solid rgba(0,229,255,0.3);box-shadow:0 0 18px rgba(0,229,255,0.12);border-radius:12px;padding:12px 14px;z-index:5;max-width:92%;';
  pinForm.innerHTML='<div id="pin-head" style="font-family:\'Space Grotesk\',sans-serif;font-size:12px;color:#f0a030;margin-bottom:8px;">Nice spot. Leave your email and Daniel will wave back.</div>'
    +'<div style="display:flex;gap:6px;"><input id="pin-email" type="email" placeholder="you@company.com" style="background:#07070f;border:1px solid rgba(240,240,248,0.15);border-radius:8px;padding:8px 10px;color:#f0f0f8;font-size:13px;width:180px;outline:none;">'
    +'<button id="pin-submit" style="background:#f0a030;color:#07070f;border:none;border-radius:8px;padding:8px 14px;font-family:\'Space Grotesk\',sans-serif;font-weight:600;font-size:13px;cursor:pointer;">Pin me</button></div>'
    +'<div id="pin-note" style="font-size:10px;color:rgba(240,240,248,0.35);margin-top:7px;">Just a hello — no spam, ever.</div>';
  panel.appendChild(pinForm);
  const pinEmail=pinForm.querySelector('#pin-email'), pinNote=pinForm.querySelector('#pin-note'), pinHead=pinForm.querySelector('#pin-head');
  pinForm.querySelector('#pin-submit').addEventListener('click',submitPin);
  pinEmail.addEventListener('keydown',e=>{if(e.key==='Enter')submitPin();});

  async function submitPin(){
    const email=pinEmail.value.trim();
    if(!/^\S+@\S+\.\S+$/.test(email)){pinEmail.focus();pinNote.textContent='That email doesn’t look right.';return;}
    pinNote.textContent='Pinning…';
    try{
      const r=await fetch('/api/globe/pin',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({lat:pending.lat,lng:pending.lng,email})});
      const d=await r.json();
      if(!r.ok)throw new Error(d.error||'Failed');
      myPin=pending;pending=null;
      pins.push({lat:myPin.lat,lng:myPin.lng});
      try{localStorage.setItem('dw_globe_pin',JSON.stringify(myPin));}catch(e){}
      pinNote.textContent='You’re on the map. ✓';
      setTimeout(()=>{pinForm.style.display='none';},1600);
    }catch(err){pinNote.textContent=err.message||'Something went wrong — try again.';}
  }

  /* tap position → lat/lng on the front of the sphere (inverse of the render) */
  function tapToLatLng(clientX,clientY){
    const r=canvas.getBoundingClientRect();
    const cx=r.width/2, cy=r.height/2, R=Math.min(r.width,r.height)*0.34;
    const nx=(clientX-r.left-cx)/R, ny=-(clientY-r.top-cy)/R;
    const rr=nx*nx+ny*ny;
    if(rr>1)return null;
    const nz=Math.sqrt(1-rr);
    /* undo tilt (rotX), then unwind rotY */
    const c=Math.cos(rotX), s=Math.sin(rotX);
    const y0=ny*c+nz*s, z0=-ny*s+nz*c;
    const lat=Math.asin(Math.max(-1,Math.min(1,y0)))*180/Math.PI;
    let lng=(Math.atan2(nx,z0)-rotY)*180/Math.PI;
    lng=((lng+180)%360+360)%360-180;
    return {lat,lng};
  }

  function resize(){
    dpr=Math.min(window.devicePixelRatio||1,2);
    const r=panel.getBoundingClientRect();
    W=r.width;H=r.height;
    canvas.width=W*dpr;canvas.height=H*dpr;
    canvas.style.width=W+'px';canvas.style.height=H+'px';
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }

  function spherePoint(latDeg,lngDeg){
    const la=latDeg*Math.PI/180, ln=lngDeg*Math.PI/180+rotY;
    const x=Math.cos(la)*Math.sin(ln), y=Math.sin(la), z=Math.cos(la)*Math.cos(ln);
    /* tilt about X */
    const c=Math.cos(rotX),s=Math.sin(rotX);
    return [x, y*c-z*s, y*s+z*c];
  }

  function project(p,R,cx,cy){
    const d=3.4,sc=d/(d-p[2]);
    return {x:cx+p[0]*R*sc, y:cy-p[1]*R*sc, z:p[2]};
  }

  function drawCircle(pts,style,width){
    ctx.beginPath();
    pts.forEach((q,i)=>i?ctx.lineTo(q.x,q.y):ctx.moveTo(q.x,q.y));
    ctx.strokeStyle=style;ctx.lineWidth=width;ctx.stroke();
  }

  function draw(){
    ctx.clearRect(0,0,W,H);
    const cx=W/2, cy=H/2, R=Math.min(W,H)*0.34;

    /* soft amber core glow */
    const glow=ctx.createRadialGradient(cx,cy,R*0.2,cx,cy,R*1.5);
    glow.addColorStop(0,AMBER(0.05));glow.addColorStop(1,AMBER(0));
    ctx.fillStyle=glow;ctx.fillRect(0,0,W,H);

    /* faint graticule — subtle now the landmass carries the shape */
    for(let lat=-60;lat<=60;lat+=30){
      const front=[],back=[];
      for(let k=0;k<=72;k++){
        const q=project(spherePoint(lat,k*5),R,cx,cy);
        (q.z>0?front:back).push({k,q});
      }
      [[back,0.04],[front,0.10]].forEach(([half,al])=>{
        let run=[];
        for(let i=0;i<half.length;i++){
          if(i>0&&half[i].k!==half[i-1].k+1){ if(run.length>1)drawCircle(run,BLUE(al),0.6); run=[]; }
          run.push(half[i].q);
        }
        if(run.length>1)drawCircle(run,BLUE(al),0.6);
      });
    }
    for(let lng=0;lng<360;lng+=45){
      const front=[],back=[];
      for(let k=0;k<=60;k++){
        const q=project(spherePoint(-90+k*3,lng),R,cx,cy);
        (q.z>0?front:back).push({k,q});
      }
      [[back,0.03],[front,0.08]].forEach(([half,al])=>{
        let run=[];
        for(let i=0;i<half.length;i++){
          if(i>0&&half[i].k!==half[i-1].k+1){ if(run.length>1)drawCircle(run,BLUE(al),0.6); run=[]; }
          run.push(half[i].q);
        }
        if(run.length>1)drawCircle(run,BLUE(al),0.6);
      });
    }

    /* ── continents: rotate the precomputed land dots with the globe ── */
    const cly=Math.cos(rotY),sly=Math.sin(rotY),clx=Math.cos(rotX),slx=Math.sin(rotX);
    const d=3.4;
    landDots.forEach(v=>{
      const x1=v[0]*cly+v[2]*sly, z1=-v[0]*sly+v[2]*cly;
      const y2=v[1]*clx-z1*slx, z2=v[1]*slx+z1*clx;
      if(z2<=0.02)return;                       /* front hemisphere only */
      const sc=d/(d-z2);
      const px=cx+x1*R*sc, py=cy-y2*R*sc;
      const al=0.14+z2*0.50;
      const sz=1.1+z2*1.2;
      ctx.fillStyle=WHITE(al.toFixed(3));
      ctx.fillRect(px-sz/2,py-sz/2,sz,sz);
    });

    /* limb (outline circle) */
    ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);
    ctx.strokeStyle=WHITE(0.22);ctx.lineWidth=1;ctx.stroke();

    /* outcome nodes */
    NODES.forEach((N,i)=>{
      const q=project(spherePoint(N.lat,N.lng),R,cx,cy);
      const front=q.z>0;
      const pulse=reduced?0.6:0.6+0.4*Math.sin(t*2+i*1.6);
      if(front){
        /* connector tick + glowing node + label */
        ctx.save();
        ctx.shadowColor='rgba(240,160,48,0.6)';ctx.shadowBlur=10;
        ctx.beginPath();ctx.arc(q.x,q.y,4.2,0,Math.PI*2);
        ctx.fillStyle=AMBER((0.55+0.35*pulse).toFixed(3));ctx.fill();
        ctx.restore();
        ctx.beginPath();ctx.arc(q.x,q.y,7.5,0,Math.PI*2);
        ctx.strokeStyle=AMBER(0.30);ctx.lineWidth=1;ctx.stroke();
        const side=q.x>cx?1:-1;
        ctx.beginPath();ctx.moveTo(q.x+side*10,q.y);ctx.lineTo(q.x+side*22,q.y);
        ctx.strokeStyle=WHITE(0.30);ctx.lineWidth=1;ctx.stroke();
        ctx.font="700 13px 'Space Grotesk', sans-serif";
        ctx.textAlign=side>0?'left':'right';ctx.textBaseline='middle';
        ctx.fillStyle=AMBER(0.9);
        ctx.fillText(N.num, q.x+side*27, q.y-8);
        ctx.font="9px 'Space Grotesk', sans-serif";
        ctx.fillStyle=WHITE(0.55);
        ctx.fillText(N.label, q.x+side*27, q.y+7);
      } else {
        /* seen through the globe, faint */
        ctx.beginPath();ctx.arc(q.x,q.y,2.5,0,Math.PI*2);
        ctx.fillStyle=AMBER(0.14);ctx.fill();
      }
    });

    /* visitor pins — locations of people who marked themselves */
    pins.forEach(pn=>{
      const q=project(spherePoint(pn.lat,pn.lng),R,cx,cy);
      if(q.z>0){
        ctx.beginPath();ctx.arc(q.x,q.y,1.8,0,Math.PI*2);
        ctx.fillStyle=BLUE(0.65);ctx.fill();
      }
    });

    /* my pin — amber ring */
    if(myPin){
      const q=project(spherePoint(myPin.lat,myPin.lng),R,cx,cy);
      if(q.z>0){
        ctx.beginPath();ctx.arc(q.x,q.y,3,0,Math.PI*2);ctx.fillStyle=AMBER(0.9);ctx.fill();
        ctx.beginPath();ctx.arc(q.x,q.y,6.5,0,Math.PI*2);ctx.strokeStyle=AMBER(0.4);ctx.lineWidth=1;ctx.stroke();
      }
    }

    /* pending pin — pulsing crosshair awaiting the email */
    if(pending){
      const q=project(spherePoint(pending.lat,pending.lng),R,cx,cy);
      if(q.z>0){
        const pr=5+2.5*Math.sin(t*5);
        ctx.beginPath();ctx.arc(q.x,q.y,3,0,Math.PI*2);ctx.fillStyle=AMBER(0.95);ctx.fill();
        ctx.beginPath();ctx.arc(q.x,q.y,pr+4,0,Math.PI*2);ctx.strokeStyle=AMBER(0.5);ctx.lineWidth=1.2;ctx.stroke();
      }
    }

    /* hint, fades once touched */
    if(!draw.touched){
      ctx.font="10px 'Space Grotesk', sans-serif";ctx.textAlign='center';
      ctx.fillStyle=WHITE(0.30);
      ctx.fillText('DRAG TO ROTATE · CLICK TO PIN YOURSELF', cx, cy+R+26);
    }
  }

  let gframe=0;
  function loop(){
    t+=0.016;
    if(!dragging){
      rotY+=spin+vel;
      vel*=0.95;                              /* momentum decay after release */
    }
    rotX+= (Math.max(-0.9,Math.min(0.9,rotX))-rotX);
    /* self-heal: panel may have been hidden (display:none) when first sized */
    if(++gframe%30===0){
      const r=panel.getBoundingClientRect();
      if(Math.abs(W-r.width)>1||Math.abs(H-r.height)>1)resize();
    }
    if(W>0)draw();
    requestAnimationFrame(loop);
  }

  function startDrag(x,y){dragging=true;lastX=x;lastY=y;vel=0;moved=0;draw.touched=true;canvas.style.cursor='grabbing';}
  function moveDrag(x,y){
    if(!dragging)return;
    moved+=Math.abs(x-lastX)+Math.abs(y-lastY);
    rotY+=(x-lastX)*0.006;
    rotX=Math.max(-0.9,Math.min(0.9,rotX+(y-lastY)*0.004));
    vel=(x-lastX)*0.0012;
    lastX=x;lastY=y;
    if(reduced)draw();
  }
  function endDrag(x,y){
    if(dragging&&moved<6&&typeof x==='number'){
      /* a tap, not a drag → place a pin where they clicked */
      const hit=tapToLatLng(x,y);
      if(hit){
        pending=hit;
        const country=countryAt(hit.lat,hit.lng);
        pinHead.textContent=country
          ? 'Nice spot — '+country+'. Leave your email and Daniel will wave back.'
          : 'Mid-ocean? Bold choice. Leave your email and Daniel will wave back.';
        pinForm.style.display='block';
        pinNote.textContent='Just a hello — no spam, ever.';
        setTimeout(()=>pinEmail.focus(),50);
      } else { pending=null; pinForm.style.display='none'; }
    }
    dragging=false;canvas.style.cursor='grab';
    if(reduced)draw();
  }

  canvas.addEventListener('mousedown',e=>startDrag(e.clientX,e.clientY));
  window.addEventListener('mousemove',e=>moveDrag(e.clientX,e.clientY));
  window.addEventListener('mouseup',e=>endDrag(e.clientX,e.clientY));
  canvas.addEventListener('touchstart',e=>{startDrag(e.touches[0].clientX,e.touches[0].clientY);},{passive:true});
  canvas.addEventListener('touchmove',e=>{moveDrag(e.touches[0].clientX,e.touches[0].clientY);},{passive:true});
  canvas.addEventListener('touchend',e=>{const c=e.changedTouches[0];endDrag(c?c.clientX:undefined,c?c.clientY:undefined);});
  window.addEventListener('resize',resize);

  resize();
  if(reduced){draw();}
  else loop();
})();

/* ════ JARVIS DASHBOARD ════ */
(function(){
  const $=id=>document.getElementById(id);
  if(!$('hud-time'))return;
  const reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;

  /* status bar: clock + fake load metrics (random walk) */
  let cpu=34,mem=52;
  setInterval(()=>{ $('hud-time').textContent=new Date().toLocaleTimeString('en-GB'); },1000);
  setInterval(()=>{
    cpu=Math.max(12,Math.min(88,cpu+(Math.random()-0.5)*9));
    mem=Math.max(30,Math.min(80,mem+(Math.random()-0.5)*4));
    $('hud-cpu').textContent=cpu.toFixed(0)+'%';
    $('hud-mem').textContent=mem.toFixed(0)+'%';
  },850);

  /* streaming terminal */
  const LOGS=[
    'spawn agent.discovery --session={S}',
    'claude.messages.create tokens={T} ok',
    'vector.index query k=12 ... {M}ms',
    'pipeline.report render p95=1.2s',
    'db.pool acquire conn=4/20',
    'webhook.gocardless sig=verified',
    'guardrail.scan pii=none risk=low',
    'embed.batch 128/128 complete',
    'cache.layer hit_ratio=94.{D}%',
    'router.model select=sonnet ctx=64k',
    'cron.daily_report armed 18:00Z',
    'tls.cert valid 89d remaining',
    'geo.pin lookup country=OK {M}ms',
    'audio.stream buffer=stable',
  ];
  const log=$('hud-log');
  function addLog(){
    const t=new Date().toLocaleTimeString('en-GB',{hour12:false});
    let line=LOGS[Math.floor(Math.random()*LOGS.length)]
      .replace('{S}',Math.random().toString(36).slice(2,8))
      .replace('{T}',200+Math.floor(Math.random()*900))
      .replace('{M}',3+Math.floor(Math.random()*40))
      .replace('{D}',Math.floor(Math.random()*9));
    const div=document.createElement('div');
    if(Math.random()<0.07){div.className='warn';line+='  [retry ok]';}
    div.textContent='['+t+'] '+line;
    log.appendChild(div);
    while(log.children.length>16)log.removeChild(log.firstChild);
  }
  for(let i=0;i<10;i++)addLog();
  setInterval(addLog,1400);

  /* telemetry chart - rolling line */
  const ch=$('hud-chart'),chx=ch.getContext('2d');
  const series=Array(60).fill(40);
  setInterval(()=>{ series.push(cpu+Math.random()*6-3); series.shift(); },400);
  function drawChart(){
    chx.clearRect(0,0,240,58);
    chx.beginPath();
    series.forEach((v,i)=>{ const x=i*4, y=54-(v/100)*48; i?chx.lineTo(x,y):chx.moveTo(x,y); });
    chx.strokeStyle='rgba(0,229,255,0.8)'; chx.lineWidth=1.2; chx.stroke();
    chx.lineTo(236,58); chx.lineTo(0,58); chx.closePath();
    chx.fillStyle='rgba(0,229,255,0.07)'; chx.fill();
  }

  /* audio waveform */
  const wv=$('hud-wave'),wvx=wv.getContext('2d');
  let wt=0;
  window.__hudAmp=1;
  function drawWave(){
    wt+=0.09; wvx.clearRect(0,0,240,40);
    const amp=window.__hudAmp;
    for(let i=0;i<48;i++){
      const h=(3+Math.abs(Math.sin(wt+i*0.42))*14*amp+Math.random()*2)*Math.min(1,amp);
      wvx.fillStyle=i%8===0?'rgba(240,160,48,0.75)':'rgba(0,229,255,0.55)';
      wvx.fillRect(i*5,20-h/2,3,h);
    }
  }

  /* diagnostics */
  const DIAG=['NET LINK','TLS CERT','DB POOL','API GATEWAY','MODEL ROUTER','RATE LIMITER','WEBHOOKS','EMAIL RELAY','VECTOR STORE','SCHEDULER'];
  const dg=$('hud-diag'); let di=0;
  function addDiag(){
    const name=DIAG[di++%DIAG.length];
    const warn=Math.random()<0.08;
    const div=document.createElement('div');
    if(warn)div.className='warn';
    div.innerHTML=name.padEnd(14,'\u00a0')+' <b>'+(warn?'RECHECK':'OK')+'</b>';
    dg.appendChild(div);
    while(dg.children.length>5)dg.removeChild(dg.firstChild);
  }
  for(let i=0;i<5;i++)addDiag();
  setInterval(addDiag,2100);

  function hudLoop(){ drawChart(); drawWave(); requestAnimationFrame(hudLoop); }
  if(!reduced)hudLoop(); else {drawChart();drawWave();}

  /* mouse-tilt parallax on panels + service cards */
  if(!reduced){
    let pend=null;
    document.addEventListener('mousemove',e=>{ pend={x:e.clientX,y:e.clientY}; },{passive:true});
    (function tiltLoop(){
      if(pend){
        document.querySelectorAll('.tilt,.service-card').forEach(el=>{
          const r=el.getBoundingClientRect();
          if(r.width===0)return;
          const dx=(pend.x-(r.left+r.width/2))/r.width, dy=(pend.y-(r.top+r.height/2))/r.height;
          if(Math.abs(dx)<2.5&&Math.abs(dy)<2.5){
            el.style.setProperty('--ty',(dx*2.2)+'deg');
            el.style.setProperty('--tx',(-dy*2.2)+'deg');
          } else { el.style.setProperty('--ty','0deg'); el.style.setProperty('--tx','0deg'); }
        });
        pend=null;
      }
      requestAnimationFrame(tiltLoop);
    })();
  }

  /* ripple on buttons */
  document.addEventListener('click',e=>{
    const b=e.target.closest('.btn-primary,.nav-cta,.chat-send,.modal-pay-btn,#hud-mic,#pin-submit');
    if(!b)return;
    const rect=b.getBoundingClientRect();
    const r=document.createElement('span');
    r.className='ripple';
    r.style.left=(e.clientX-rect.left)+'px';
    r.style.top=(e.clientY-rect.top)+'px';
    b.appendChild(r);
    setTimeout(()=>r.remove(),650);
  });

  /* command bar routes into the AI chat */
  function sendCommand(text){
    if(!text)return;
    if(!chatOpen)toggleChat();
    const inp=document.getElementById('chat-input');
    inp.value=text;
    sendChat();
    $('hud-input').value='';
  }
  $('hud-input').addEventListener('keydown',e=>{ if(e.key==='Enter')sendCommand(e.target.value.trim()); });

  /* mic: real voice commands where the browser supports it */
  const SR=window.SpeechRecognition||window.webkitSpeechRecognition;
  const mic=$('hud-mic');
  if(SR){
    const rec=new SR(); rec.lang='en-GB'; rec.interimResults=false;
    let listening=false;
    mic.addEventListener('click',()=>{
      if(listening){rec.stop();return;}
      try{ rec.start(); listening=true; mic.classList.add('listening'); window.__hudAmp=2.2; }catch(e){}
    });
    rec.onresult=ev=>{ const said=ev.results[0][0].transcript; $('hud-input').value=said; sendCommand(said); };
    rec.onend=()=>{ listening=false; mic.classList.remove('listening'); window.__hudAmp=1; };
    rec.onerror=()=>{ listening=false; mic.classList.remove('listening'); window.__hudAmp=1; };
  } else {
    mic.addEventListener('click',()=>{ $('hud-input').focus(); });
  }
})();

/* ════ AI CORE VORTEX ════
   The visual heart of the page: a bright 3D particle spiral endlessly
   collapsing into a glowing nucleus — arc-reactor energy, drawn additively. */
(function(){
  const canvas=document.getElementById('core-canvas');
  if(!canvas)return;
  const hero=document.getElementById('hero');
  const ctx=canvas.getContext('2d');
  const reduced=window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  let W,H,dpr=1;

  function resize(){
    dpr=Math.min(window.devicePixelRatio||1,2);
    const r=hero.getBoundingClientRect();
    W=r.width;H=r.height;
    canvas.width=W*dpr;canvas.height=H*dpr;
    canvas.style.width=W+'px';canvas.style.height=H+'px';
    ctx.setTransform(dpr,0,0,dpr,0,0);
  }

  /* particles on 3 spiral arms, flowing inward forever */
  const N=650, parts=[];
  for(let i=0;i<N;i++)parts.push({
    arm:i%3,
    t:Math.random(),                     /* 1 = outer rim, 0 = nucleus */
    y:(Math.random()-0.5),
    sp:0.0009+Math.random()*0.0016,
    sz:0.7+Math.random()*1.7
  });

  const TILT=1.02;
  let time=0;

  function draw(){
    ctx.clearRect(0,0,W,H);
    const cx=W/2, cy=H*0.52;
    const R=Math.min(W,H)*0.30;
    const ry=time*0.14, spin=time*0.55;
    const cyt=Math.cos(TILT),syt=Math.sin(TILT);
    const cyr=Math.cos(ry),syr=Math.sin(ry);
    const amp=(window.__hudAmp||1);

    ctx.globalCompositeOperation='lighter';

    /* nucleus glow — the reactor heart */
    const pulse=reduced?1:1+0.07*Math.sin(time*3)+((amp-1)*0.25);
    const nr=R*0.16*pulse;
    let g=ctx.createRadialGradient(cx,cy,0,cx,cy,nr*3.2);
    g.addColorStop(0,'rgba(255,244,220,0.95)');
    g.addColorStop(0.12,'rgba(240,160,48,0.75)');
    g.addColorStop(0.35,'rgba(0,229,255,0.22)');
    g.addColorStop(1,'rgba(0,229,255,0)');
    ctx.fillStyle=g;
    ctx.beginPath();ctx.arc(cx,cy,nr*3.2,0,Math.PI*2);ctx.fill();

    /* two thin tilted energy rings around the nucleus */
    [1.9,2.6].forEach((k,ri)=>{
      ctx.beginPath();
      for(let a=0;a<=64;a++){
        const th=a/64*Math.PI*2+(ri?-spin*0.5:spin*0.4);
        const x=Math.cos(th)*nr*k, z=Math.sin(th)*nr*k;
        const x1=x*cyr+z*syr, z1=-x*syr+z*cyr;
        const y2=-z1*syt, pz=z1*cyt;
        const sc=3.4/(3.4-pz/R);
        const px=cx+x1*sc, py=cy+y2*sc;
        a?ctx.lineTo(px,py):ctx.moveTo(px,py);
      }
      ctx.strokeStyle='rgba(0,229,255,'+(0.35-ri*0.12)+')';
      ctx.lineWidth=1.1;ctx.stroke();
    });

    /* spiral arms */
    parts.forEach(P=>{
      if(!reduced){P.t-=P.sp*amp; if(P.t<0.03){P.t=1;P.y=(Math.random()-0.5);}}
      const r=Math.pow(P.t,0.85)*R;
      const th=P.arm*2.0944 + spin + (1-P.t)*4.4;
      const x=Math.cos(th)*r, z=Math.sin(th)*r, y=P.y*R*0.05*P.t;
      /* rotate Y then tilt X */
      const x1=x*cyr+z*syr, z1=-x*syr+z*cyr;
      const y2=y*cyt-z1*syt, pz=y*syt+z1*cyt;
      const sc=3.4/(3.4-pz/R);
      const px=cx+x1*sc, py=cy+y2*sc;
      const inner=1-P.t;
      const a=0.14+inner*0.6;
      const c=P.t<0.22?'rgba(255,240,214,'+a.toFixed(3)+')'
        :P.t<0.55?'rgba(160,240,255,'+a.toFixed(3)+')'
        :'rgba(0,229,255,'+a.toFixed(3)+')';
      const sz=P.sz*(0.6+inner*1.1)*sc;
      ctx.fillStyle=c;
      ctx.fillRect(px-sz/2,py-sz/2,sz,sz);
    });

    ctx.globalCompositeOperation='source-over';
  }

  let cframe=0;
  function loop(){
    time+=0.016;
    if(++cframe%30===0){
      const r=hero.getBoundingClientRect();
      if(Math.abs(W-r.width)>1||Math.abs(H-r.height)>1)resize();
    }
    /* only render while the hero is on screen */
    if(window.scrollY<H*1.2)draw();
    requestAnimationFrame(loop);
  }

  window.addEventListener('resize',resize);
  resize();
  if(reduced){draw();}
  else loop();
})();

/* ════ NAV ════ */
window.addEventListener('scroll',()=>document.getElementById('navbar').classList.toggle('scrolled',window.scrollY>60));

/* ════ CALENDAR ════ */
const today=new Date();
let viewMonth=today.getMonth(),viewYear=today.getFullYear();
let selectedDate=null,selectedSlot=null;
let selectedServiceName='Discovery Call',selectedServicePrice=0;
const UNAVAIL_DAYS=[0,6];
const MONTHS=['January','February','March','April','May','June','July','August','September','October','November','December'];
const ALL_SLOTS=['09:00','09:30','10:00','10:30','11:00','11:30','13:00','13:30','14:00','14:30','15:00','15:30','16:00','16:30'];

/* Live availability from the server: {'YYYY-MM-DD': ['09:00', …]} per month */
const AVAIL_CACHE={};
async function fetchUnavailable(y,m){
  const key=`${y}-${String(m+1).padStart(2,'0')}`;
  if(!AVAIL_CACHE[key]){
    try{
      const r=await fetch('/api/availability?month='+key);
      const d=await r.json();
      AVAIL_CACHE[key]=d.unavailable||{};
    }catch(e){AVAIL_CACHE[key]={};}
  }
  return AVAIL_CACHE[key];
}

function dk(y,m,d){return `${y}-${String(m+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;}

async function renderCalendar(){
  document.getElementById('cal-month-label').textContent=MONTHS[viewMonth]+' '+viewYear;
  const unavail=await fetchUnavailable(viewYear,viewMonth);
  const grid=document.getElementById('cal-grid');
  grid.innerHTML='';
  const firstDow=new Date(viewYear,viewMonth,1).getDay();
  const offset=firstDow===0?6:firstDow-1;
  const daysInMonth=new Date(viewYear,viewMonth+1,0).getDate();
  for(let i=0;i<offset;i++){const e=document.createElement('div');e.className='cal-day';grid.appendChild(e);}
  for(let d=1;d<=daysInMonth;d++){
    const btn=document.createElement('button');
    btn.className='cal-day';
    btn.textContent=d;
    const key=dk(viewYear,viewMonth,d);
    const date=new Date(viewYear,viewMonth,d);
    const isPast=date<new Date(today.getFullYear(),today.getMonth(),today.getDate());
    const isWeekend=UNAVAIL_DAYS.includes(date.getDay());
    const isFull=(unavail[key]||[]).length>=ALL_SLOTS.length;
    const isToday=d===today.getDate()&&viewMonth===today.getMonth()&&viewYear===today.getFullYear();
    if(isToday)btn.classList.add('today');
    if(!isPast&&!isWeekend&&!isFull){
      btn.classList.add('available');
      if(selectedDate===key)btn.classList.add('selected');
      btn.onclick=()=>pickDate(key,d);
    }
    grid.appendChild(btn);
  }
}

async function pickDate(key,d){
  selectedDate=key;selectedSlot=null;
  renderCalendar();
  const dateObj=new Date(key+'T12:00:00');
  document.getElementById('step-time-hint').textContent=dateObj.toLocaleDateString('en-GB',{weekday:'long',day:'numeric',month:'long'});
  showStep('step-time');
  const unavail=await fetchUnavailable(viewYear,viewMonth);
  const taken=unavail[key]||[];
  const grid=document.getElementById('slots-grid');
  grid.innerHTML='';
  ALL_SLOTS.forEach(s=>{
    const el=document.createElement('div');
    el.className='slot'+(taken.includes(s)?' taken':'');
    el.textContent=s;
    if(!taken.includes(s))el.onclick=function(){pickSlot(s,this);};
    grid.appendChild(el);
  });
}

function pickSlot(slot,el){
  selectedSlot=slot;
  document.querySelectorAll('.slot').forEach(s=>s.classList.remove('selected'));
  el.classList.add('selected');
  const dateObj=new Date(selectedDate+'T12:00:00');
  const dateStr=dateObj.toLocaleDateString('en-GB',{weekday:'short',day:'numeric',month:'short'});
  document.getElementById('step-details-hint').textContent=dateStr+' · '+slot;
  document.getElementById('bsb-service').textContent=selectedServiceName;
  document.getElementById('bsb-date').textContent=dateStr;
  document.getElementById('bsb-time').textContent=slot;
  document.getElementById('bsb-price').textContent=selectedServicePrice==0?'Free':'£'+parseInt(selectedServicePrice).toLocaleString();
  showStep('step-details');
}

function showStep(id){
  document.getElementById(id).style.display='block';
  document.getElementById(id).scrollIntoView({behavior:'smooth',block:'nearest'});
}

function goBack(showId,hideId){
  document.getElementById(hideId).style.display='none';
  if(hideId==='step-time')document.getElementById('step-details').style.display='none';
}

function changeMonth(dir){
  viewMonth+=dir;
  if(viewMonth>11){viewMonth=0;viewYear++;}
  if(viewMonth<0){viewMonth=11;viewYear--;}
  renderCalendar();
}

/* ════ SERVICE SELECTOR ════ */
function setService(el,name,price){
  document.querySelectorAll('.bip-service').forEach(s=>s.classList.remove('active'));
  el.classList.add('active');
  selectedServiceName=name;selectedServicePrice=price;
  document.getElementById('bsb-service').textContent=name;
  document.getElementById('bsb-price').textContent=price==0?'Free':'£'+parseInt(price).toLocaleString();
}

/* ════ PAYMENT MODAL ════ */
function openPayModal(){
  const name=document.getElementById('book-name').value.trim();
  const email=document.getElementById('book-email').value.trim();
  if(!name){document.getElementById('book-name').focus();return;}
  if(!email){document.getElementById('book-email').focus();return;}
  const dateObj=new Date(selectedDate+'T12:00:00');
  document.getElementById('modal-service').textContent=selectedServiceName;
  document.getElementById('modal-date').textContent=dateObj.toLocaleDateString('en-GB',{weekday:'long',day:'numeric',month:'long'});
  document.getElementById('modal-time').textContent=selectedSlot;
  document.getElementById('modal-total').textContent=selectedServicePrice==0?'Free':'£'+parseInt(selectedServicePrice).toLocaleString();
  document.getElementById('pay-modal').classList.add('open');
}
function closePayModal(){document.getElementById('pay-modal').classList.remove('open');}
async function processPayment(){
  const btn=document.querySelector('.modal-pay-btn');
  btn.textContent='Processing…';btn.disabled=true;
  try{
    const res=await fetch('/api/bookings/initiate',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({
        name:document.getElementById('book-name').value.trim(),
        email:document.getElementById('book-email').value.trim(),
        company:document.getElementById('book-company').value.trim(),
        service:selectedServiceName,
        price:selectedServicePrice,
        date:selectedDate,
        time_slot:selectedSlot
      })
    });
    const data=await res.json();
    if(!res.ok) throw new Error(data.error||'Booking failed');
    if(data.free){
      // Free discovery call — confirmed immediately
      document.getElementById('modal-content').innerHTML='<div class="success-state"><div class="success-icon">✅</div><h3>Booking confirmed!</h3><p>A confirmation has been sent to your email. Daniel will be in touch with a video link shortly.</p></div>';
      setTimeout(()=>{closePayModal();location.reload();},5000);
    } else {
      // Paid booking — redirect to GoCardless
      window.location.href=data.redirectUrl;
    }
  }catch(err){
    btn.textContent='Pay now via GoCardless →';btn.disabled=false;
    alert(err.message||'Something went wrong. Please try again.');
  }
}
document.getElementById('pay-modal').addEventListener('click',function(e){if(e.target===this)closePayModal();});

// Handle return from GoCardless
(function(){
  const params=new URLSearchParams(window.location.search);
  if(params.get('confirmed')==='true'){
    setTimeout(()=>{
      document.getElementById('booking').scrollIntoView({behavior:'smooth'});
      alert('Payment confirmed! Check your email for your booking details.');
    },500);
    window.history.replaceState({},'','/');
  }
  if(params.get('error')){
    setTimeout(()=>alert('Payment was not completed. Please try again.'),500);
    window.history.replaceState({},'','/');
  }
})();

/* ════ AI CHAT ════ */
let chatOpen=false;
const chatEl=document.getElementById('chat-messages');
const AI={
  default:[
    "That's a great question. AI implementation varies significantly by industry and business size. Could you tell me a bit more about your organisation?",
    "Happy to help. Daniel specialises in exactly this area — would you like me to recommend the right service, or book a free discovery call to discuss in detail?",
    "The short answer depends on your current tech stack and team capability. A 30-minute discovery call is the fastest way to get a tailored answer — and it's free.",
  ],
  book:"You can book directly on this page — scroll to 'Book a session', pick a date and time, and payment is handled instantly via GoCardless.",
  price:"Pricing: £500 for a 60-minute strategy session, £1,500/day for AI implementation, £1,200/day for training workshops, and £5,000/month (12-month minimum, 25hrs/month) for the Fractional AI Officer retainer.",
  cred:"Daniel holds certifications from Google, Oxford University, and MIT — a rare combination of academic rigour and hands-on delivery experience.",
};
function addMsg(text,role){
  const m=document.createElement('div');m.className='msg '+role;
  const b=document.createElement('div');b.className='msg-bubble';b.textContent=text;
  const t=document.createElement('div');t.className='msg-time';t.textContent='Just now';
  m.appendChild(b);m.appendChild(t);chatEl.appendChild(m);chatEl.scrollTop=chatEl.scrollHeight;
}
function addTyping(){
  const t=document.createElement('div');t.className='msg ai';t.id='typing-ind';
  t.innerHTML='<div class="msg-bubble"><div class="typing-dots"><span></span><span></span><span></span></div></div>';
  chatEl.appendChild(t);chatEl.scrollTop=chatEl.scrollHeight;
}
function rmTyping(){const t=document.getElementById('typing-ind');if(t)t.remove();}
async function sendChat(){
  const inp=document.getElementById('chat-input');
  const text=inp.value.trim();if(!text)return;
  inp.value='';addMsg(text,'user');addTyping();
  try{
    const r=await fetch('/api/chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:text})});
    const d=await r.json();rmTyping();addMsg(d.reply||localReply(text),'ai');
  }catch(e){rmTyping();addMsg(localReply(text),'ai');}
}
function localReply(t){
  t=t.toLowerCase();
  if(t.includes('book')||t.includes('call')||t.includes('appointment'))return AI.book;
  if(t.includes('price')||t.includes('cost')||t.includes('much')||t.includes('fee'))return AI.price;
  if(t.includes('oxford')||t.includes('mit')||t.includes('google')||t.includes('certif'))return AI.cred;
  return AI.default[Math.floor(Math.random()*AI.default.length)];
}
function toggleChat(){
  chatOpen=!chatOpen;
  document.getElementById('chat-panel').classList.toggle('open',chatOpen);
  if(chatOpen&&chatEl.children.length===0){
    setTimeout(()=>addMsg("Hi! I'm Daniel's AI assistant. Ask me anything about services, pricing, or how AI could help your business — or I can help you book right now.",'ai'),300);
  }
}

